    Get YAML data from request, parse it, and return it.
    Uses safe_load to prevent arbitrary code execution from untrusted YAML input.
    '''
    if not request.is_json and not request.content_type.startswith('application/x-yaml'):
        return jsonify({"error": "Content-Type must be application/x-yaml or application/json"}), 400

    try:
        # Use safe_load instead of load to prevent YAML tags from executing arbitrary code
        data = yaml.safe_load(request.data)
        return jsonify(data)
    except yaml.YAMLError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        return jsonify({"error": "An internal error occurred"}), 500
