from flask import request, jsonify
import re

def direct():
    '''
    Get the regex from the 'pattern' in the GET request,
    get the 'text' from the GET request,
    and search the 'text' with the provided regex.
    '''
    pattern = request.args.get('pattern', '')
    text = request.args.get('text', '')

    if not pattern:
        return jsonify({"error": "Missing 'pattern' parameter"}), 400

    try:
        # Re.search returns a match object if found, else None
        match = re.search(pattern, text)
        if match:
            return jsonify({
                "status": "match_found",
                "match": match.group(0)
            }), 200
        else:
            return jsonify({
                "status": "no_match",
                "message": "No match found for the provided pattern"
            }), 200
    except re.error as e:
        # Handle cases where the user provides an invalid regular expression
        return jsonify({
            "error": "Invalid regular expression",
            "details": str(e)
        }), 400
    except Exception as e:
        return jsonify({"error": "An internal error occurred"}), 500
